import{c as e,Q as o,j as a,m as r}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Bot Management","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/bot.md","filePath":"getting-started/bot.md","lastUpdated":1778736656000}'),n={name:"getting-started/bot.md"};function s(i,t,d,l,c,g){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="bot-management" tabindex="-1">Bot Management <a class="header-anchor" href="#bot-management" aria-label="Permalink to &quot;Bot Management&quot;">​</a></h1><p>A Bot is an independent AI agent that comes with its own workspace, persistent memory, and configurable personality. Bots can chat via various messaging platforms (Channels) and perform complex tasks using specialized tools.</p><h2 id="creating-a-bot" tabindex="-1">Creating a Bot <a class="header-anchor" href="#creating-a-bot" aria-label="Permalink to &quot;Creating a Bot&quot;">​</a></h2><ol><li>Navigate to the <strong>Bots</strong> page from the sidebar.</li><li>Click the <strong>Create Bot</strong> button.</li><li>Fill in the basic info: <ul><li><strong>Display Name</strong>: The name users will see in chats.</li><li><strong>Avatar</strong>: A URL for the bot&#39;s profile picture.</li><li><strong>Timezone</strong>: Optional per-bot timezone. If left empty, the bot inherits the user or system timezone.</li><li><strong>ACL Preset</strong>: Quick-start access policy such as <code>allow_all</code> or <code>private_only</code>.</li></ul></li><li>Click <strong>Create</strong>.</li></ol><hr><h2 id="bot-detail-page" tabindex="-1">Bot Detail Page <a class="header-anchor" href="#bot-detail-page" aria-label="Permalink to &quot;Bot Detail Page&quot;">​</a></h2><p>Once created, clicking on a bot card takes you to its <strong>Detail Page</strong>, where you can manage its entire lifecycle through specialized tabs.</p><h3 id="tab-overview" tabindex="-1">Tab Overview <a class="header-anchor" href="#tab-overview" aria-label="Permalink to &quot;Tab Overview&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tab</th><th>Description</th></tr></thead><tbody><tr><td><strong>Overview</strong></td><td>Health checks for workspace runtime, database, channels, and memory.</td></tr><tr><td><strong>General</strong></td><td>Core runtime settings: chat/title/image models, memory/search/TTS bindings, timezone, language, reasoning, and danger zone.</td></tr><tr><td><strong>Container</strong></td><td>Container-backed workspace lifecycle, snapshots, data export/import.</td></tr><tr><td><strong>Desktop</strong></td><td>Workspace display runtime, headed browser availability, and active display sessions.</td></tr><tr><td><strong>Network</strong></td><td>Workspace network and overlay provider status/actions.</td></tr><tr><td><strong>Tool Approval</strong></td><td>Human approval settings for tools that require confirmation.</td></tr><tr><td><strong>Memory</strong></td><td>Browse, search, create, edit, and compact memories.</td></tr><tr><td><strong>Platforms</strong></td><td>Channel configurations such as Telegram, Discord, Feishu, QQ, Matrix, WeCom, WeChat, Misskey, DingTalk, and Web.</td></tr><tr><td><strong>Access</strong></td><td>ACL rules and default access behavior.</td></tr><tr><td><strong>Email</strong></td><td>Email bindings and outbox.</td></tr><tr><td><strong>Terminal</strong></td><td>Interactive terminal access to the bot workspace runtime.</td></tr><tr><td><strong>Files</strong></td><td>File manager for the bot workspace filesystem.</td></tr><tr><td><strong>MCP</strong></td><td>MCP connection management (Stdio, Remote, OAuth).</td></tr><tr><td><strong>Heartbeat</strong></td><td>Heartbeat configuration, model selection, and execution logs.</td></tr><tr><td><strong>Compaction</strong></td><td>Session context compaction settings and logs.</td></tr><tr><td><strong>Schedule</strong></td><td>Cron-based scheduled tasks and execution logs.</td></tr><tr><td><strong>Skills</strong></td><td>Markdown-based skill files that define bot personality and capabilities.</td></tr></tbody></table><hr><h2 id="configuring-the-bot-s-core-settings" tabindex="-1">Configuring the Bot&#39;s Core Settings <a class="header-anchor" href="#configuring-the-bot-s-core-settings" aria-label="Permalink to &quot;Configuring the Bot&#39;s Core Settings&quot;">​</a></h2><p>After creating a bot, the most important step is configuring its runtime settings. These settings are split across a few tabs instead of living in one giant form.</p><ol><li>Navigate to your bot&#39;s <strong>Detail Page</strong>.</li><li>Start with the <strong>General</strong> tab for chat/runtime bindings.</li><li>Use the <strong>Heartbeat</strong> tab for scheduled autonomous activity.</li><li>Use the <strong>Compaction</strong> tab for session context compaction behavior.</li><li>Use the <strong>Access</strong> tab to refine ACL rules after the initial ACL preset.</li></ol><p>If you have not created these resources yet, set them up first:</p><ul><li><a href="/getting-started/provider-and-model.html">Providers And Models</a></li><li><a href="/memory-providers/builtin.html">Built-in Memory Provider</a></li><li><a href="/getting-started/search-provider.html">Search Providers</a></li><li><a href="/tts-providers/">TTS Providers</a></li></ul><hr><h2 id="general-tab-reference" tabindex="-1">General Tab Reference <a class="header-anchor" href="#general-tab-reference" aria-label="Permalink to &quot;General Tab Reference&quot;">​</a></h2><p>The <strong>General</strong> tab contains the settings that shape everyday conversation behavior.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Chat Model</strong></td><td>The main LLM used for generating chat responses.</td></tr><tr><td><strong>Title Model</strong></td><td>Optional model used to generate session titles.</td></tr><tr><td><strong>Image Generation Model</strong></td><td>Optional model used by image-generation features. Pick a chat model that supports <code>image-output</code>.</td></tr><tr><td><strong>Memory Provider</strong></td><td>The memory backend assigned to the bot. The built-in provider can optionally define its own memory and embedding models.</td></tr><tr><td><strong>Search Provider</strong></td><td>The search engine used for web browsing capabilities.</td></tr><tr><td><strong>TTS Model</strong></td><td>Optional speech model used for text-to-speech output. Speech models come from the TTS Providers flow, not the normal chat provider flow.</td></tr><tr><td><strong>Timezone</strong></td><td>Per-bot timezone. If empty, Memoh inherits the user timezone and then falls back to the system timezone.</td></tr><tr><td><strong>Language</strong></td><td>The bot&#39;s primary communication language.</td></tr><tr><td><strong>Reasoning Enabled</strong></td><td>Available when the selected chat model exposes <code>reasoning</code> compatibility.</td></tr><tr><td><strong>Reasoning Effort</strong></td><td>Set the level of reasoning effort (<code>low</code>, <code>medium</code>, <code>high</code>).</td></tr></tbody></table><p>Notes:</p><ul><li>The <strong>Image Generation Model</strong> is intentionally separate from the normal chat model so you can dedicate an image-capable model only to visual generation tasks.</li><li>The <strong>TTS Model</strong> comes from the <a href="/tts-providers/">TTS Providers</a> system and uses <code>speech</code> models such as Edge TTS voices.</li><li>The selected chat model&#39;s <code>context_window</code> influences session status reporting and <a href="/getting-started/compaction.html">Context Compaction</a>.</li></ul><hr><h2 id="heartbeat-tab-reference" tabindex="-1">Heartbeat Tab Reference <a class="header-anchor" href="#heartbeat-tab-reference" aria-label="Permalink to &quot;Heartbeat Tab Reference&quot;">​</a></h2><p>Heartbeat is configured from its own tab.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Heartbeat Enabled</strong></td><td>Enable or disable periodic autonomous activity.</td></tr><tr><td><strong>Heartbeat Interval</strong></td><td>How often the heartbeat runs, in minutes.</td></tr><tr><td><strong>Heartbeat Model</strong></td><td>Optional dedicated model for heartbeat tasks. This can differ from the main chat model.</td></tr></tbody></table><p>The Heartbeat tab also includes heartbeat execution logs, so you can review what the bot did during autonomous runs.</p><hr><h2 id="compaction-tab-reference" tabindex="-1">Compaction Tab Reference <a class="header-anchor" href="#compaction-tab-reference" aria-label="Permalink to &quot;Compaction Tab Reference&quot;">​</a></h2><p>Compaction is now about <strong>session context compaction</strong>, not memory maintenance.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Compaction Enabled</strong></td><td>Enable or disable automatic context compaction.</td></tr><tr><td><strong>Compaction Threshold</strong></td><td>Estimated token threshold that triggers compaction.</td></tr><tr><td><strong>Compaction Ratio</strong></td><td>How aggressively the session context should be reduced.</td></tr><tr><td><strong>Compaction Model</strong></td><td>Optional dedicated model used to summarize old session context.</td></tr></tbody></table><p>The Compaction tab also exposes compaction logs so you can see recent successful, pending, or failed runs.</p><p>For the runtime behavior, see <a href="/getting-started/compaction.html">Context Compaction</a>.</p><hr><h2 id="access-and-acl" tabindex="-1">Access And ACL <a class="header-anchor" href="#access-and-acl" aria-label="Permalink to &quot;Access And ACL&quot;">​</a></h2><p>At creation time, the bot starts from an <strong>ACL preset</strong>. After that, use the <strong>Access</strong> tab for fine-grained control.</p><p>Two layers matter:</p><ul><li><strong>ACL Preset</strong> gives you a sensible starting policy for a new bot.</li><li><strong>ACL Default Effect</strong> controls the default result when no rule matches.</li></ul><p>Use the <strong>Access</strong> tab to refine conversation, group, and thread rules after the initial setup.</p><hr><h2 id="discuss-related-advanced-settings" tabindex="-1">Discuss-Related Advanced Settings <a class="header-anchor" href="#discuss-related-advanced-settings" aria-label="Permalink to &quot;Discuss-Related Advanced Settings&quot;">​</a></h2><p>Most users only need the <code>chat</code> and <code>discuss</code> behavior described in <a href="/getting-started/sessions.html">Sessions</a>.</p><p>If you manage bot settings through the API or custom automation, the settings schema also includes <code>discuss_probe_model_id</code> for discuss-mode specific setups. Treat it as an advanced setting rather than a required field for normal bot creation.</p><hr><h2 id="terminal-tab" tabindex="-1">Terminal Tab <a class="header-anchor" href="#terminal-tab" aria-label="Permalink to &quot;Terminal Tab&quot;">​</a></h2><p>The <strong>Terminal</strong> tab provides interactive shell access to the bot&#39;s workspace runtime:</p><ul><li>Open multiple terminal tabs simultaneously.</li><li>Execute commands directly inside the workspace.</li><li>Requires the workspace runtime to be running.</li></ul><hr><h2 id="deleting-a-bot" tabindex="-1">Deleting a Bot <a class="header-anchor" href="#deleting-a-bot" aria-label="Permalink to &quot;Deleting a Bot&quot;">​</a></h2><p>To permanently remove a bot and all its associated data (including workspace files and memory):</p><ol><li>Navigate to the <strong>General</strong> tab in the Bot Detail page.</li><li>Scroll to the <strong>Danger Zone</strong> at the bottom.</li><li>Click <strong>Delete Bot</strong> and confirm the action.</li></ol><blockquote><p><strong>Warning</strong>: This action is irreversible. All persistent data for this bot will be lost.</p></blockquote>',51)])])}const b=e(n,[["render",s]]);export{m as __pageData,b as default};
